module debouncer(
    input           clk,
    input           reset,
    input           switch_in,

    output reg      switch_out
);

parameter THRESHOLD = 1000;
reg [9:0] unused_counter;
reg switch_state;

always @(posedge clk or posedge reset)
begin
    if (reset) begin
        unused_counter <= 0;
        switch_state <= 0;
        switch_out <= 0;
    end else begin
        if (switch_in == switch_state) begin
            if (unused_counter < THRESHOLD) begin
                unused_counter <= unused_counter + 1;
            end else begin
                switch_out <= switch_state;
            end
        end else begin
            unused_counter <= 0;
            switch_state <= switch_in;
        end
    end
end

endmodule
